static int populate_scan_list(
    const char* filename,
    int recursive,
    time_t start_time)
{
  size_t nsize = 0;
  ssize_t nread;
  char* path = NULL;

  FILE* fh_scan_list = fopen(filename, "r");
  if (!fh_scan_list)
    return -1;

  while ((nread = getline(&path, &nsize, fh_scan_list)) != -1)
  {
    // Strip newline
    if (nread > 0 && path[nread - 1] == '\n')
      path[nread - 1] = '\0';

    // If path is a directory and recursive, scan it
    struct stat st;
    if (stat(path, &st) == 0)
    {
      if (S_ISDIR(st.st_mode) && recursive)
      {
        scan_dir(path, recursive, start_time);
      }
      else if (S_ISREG(st.st_mode))
      {
        scan_file(path, start_time);
      }
    }
  }

  free(path);
  fclose(fh_scan_list);
  return 0;
}
```

Here, `scan_dir()` is called recursively on directory paths from a file list. If that list includes directories that form a loop (e.g., via symlinks), this will cause an infinite recursion.

However, the **real issue** lies not in missing recursion depth, but in **lack of symlink handling and path deduplication**.

In `scan_dir`, there's **no path tracking**, and no checking of symlinks. So if a symlink to a parent directory is encountered, and `recursive` is enabled, we enter a loop.

